class OfferStatus(str, Enum):
    ACTIVE = "active"
    PAUSED = "paused"
    CLOSED = "closed"
    CANCELLED = "cancelled"


class DealStatus(str, Enum):
    ESCROW_LOCKED = "escrow_locked"      # buyer payment is locked by internal ledger
    PAID = "paid"                        # legacy status; not used for external payments
    RELEASED = "released"                # locked buyer payment released to seller
    CANCELLED = "cancelled"              # cancelled before release, payment refunded to buyer
    DISPUTED = "disputed"                # admin must resolve
    RESOLVED_BUYER = "resolved_buyer"    # admin refunded locked payment to buyer
    RESOLVED_SELLER = "resolved_seller"  # admin released locked payment to seller


