@router.message(WithdrawForm.amount)
async def withdraw_amount(message: Message, state: FSMContext) -> None:
    db.upsert_user(message)
    try:
        amount = money(message.text)
    except ValueError as e:
        await message.answer(str(e))
        return
    data = await state.get_data()
    asset = data["asset"]
    available, _locked = db.get_balance(message.from_user.id, asset)
    if available < amount:
        await message.answer(f"Недостаточно баланса. Доступно: <code>{fmt(available)}</code> {currency_html(asset)}")
        return
    current = db.get_requisites(message.from_user.id)
    await state.update_data(amount=str(amount))
    await state.set_state(WithdrawForm.details)
    text = (
        f"Введите реквизиты для вывода <b>{fmt(amount)}</b> {currency_html(asset)}.\n"
        "Например: сеть/кошелёк, карта/банк, ФИО при необходимости."
    )
    if current:
        text += "\n\nМожно отправить эти же реквизиты или новые:\n" + html_escape(current)
    await message.answer(text)


@router.message(WithdrawForm.details)
async def withdraw_details(message: Message, state: FSMContext, bot: Bot) -> None:
    db.upsert_user(message)
    data = await state.get_data()
    try:
        asset = normalize_currency(data["asset"])
        amount = Decimal(data["amount"])
        details = (message.text or "").strip()
        request_id = db.create_withdrawal_request(message.from_user.id, asset, amount, details)
        db.set_requisites(message.from_user.id, details)
    except (ValueError, KeyError) as e:
        await message.answer(f"Ошибка: {html_escape(str(e))}")
        return
    await state.clear()
    await message.answer(
        f"✅ Заявка на вывод #{request_id} создана.\n"
        f"Сумма <b>{fmt(amount)}</b> {currency_html(asset)} заблокирована до обработки админом.",
        reply_markup=main_menu(message.from_user.id),
    )
    for admin_id in ADMIN_IDS:
        await safe_send(
            bot,
            admin_id,
            "🏧 Новая заявка на вывод\n\n"
            f"ID заявки: <code>{request_id}</code>\n"
            f"Пользователь: <code>{message.from_user.id}</code>\n"
            f"Сумма: <b>{fmt(amount)}</b> {currency_html(asset)}\n"
            f"Реквизиты:\n{html_escape(details)}\n\n"
            f"<code>/withdraw_done {request_id}</code> — выплатил\n"
            f"<code>/withdraw_refund {request_id}</code> — отменить и вернуть баланс",
        )


async def send_withdrawals(message: Message) -> None:
    rows = db.list_pending_withdrawals()
    if not rows:
        await message.answer("Заявок на вывод нет", reply_markup=main_menu())
        return
    text = "<b>🏧 Заявки на вывод</b>\n\n"
    for r in rows:
        text += (
            f"#{r['id']} | user <code>{r['user_id']}</code> | "
            f"<b>{html_escape(r['amount'])}</b> {currency_html(r['asset'])}\n"
            f"Реквизиты: {html_escape(r['details'])}\n\n"
        )
    text += "<code>/withdraw_done ID</code> или <code>/withdraw_refund ID</code>"
    await message.answer(text)


